const fs = require("node:fs");
const path = require("node:path");
const os = require("node:os");
const { spawn } = require("node:child_process");
const { app } = require("electron");

/**
 * Cria manager do whisper-cli para transcricao local por execucao isolada.
 */
function createWhisperCliManager(options) {
  const logger = options?.logger || {
    info: () => {},
    warn: () => {},
    error: () => {}
  };
  const configuredPath = options?.binaryPath || process.env.WHISPER_CLI_PATH || "";
  const configuredModel = options?.modelPath || process.env.WHISPER_MODEL_PATH || "";
  const modelManager = options?.modelManager;
  const defaultBinaryName = process.platform === "win32" ? "whisper-cli.exe" : "whisper-cli";

  let status = "idle";
  let lastError = "";
  let lastRunAtIso = "";

  function resolveBinaryPath() {
    const candidates = [
      configuredPath,
      path.join(app.getPath("userData"), "runtime", defaultBinaryName),
      path.join(process.cwd(), "bin", defaultBinaryName)
    ].filter(Boolean);

    return candidates.find((candidate) => fs.existsSync(candidate)) || "";
  }

  function resolveModelPath() {
    if (configuredModel && fs.existsSync(configuredModel)) {
      return configuredModel;
    }

    if (modelManager) {
      const managedPath = modelManager.resolveModelPath("whisper");
      if (managedPath) {
        return managedPath;
      }
    }

    const localModel = path.join(app.getPath("userData"), "runtime", "models", "ggml-base.bin");
    if (fs.existsSync(localModel)) {
      return localModel;
    }

    return "";
  }

  function getStatus() {
    return {
      state: status,
      binaryPath: resolveBinaryPath(),
      modelPath: resolveModelPath(),
      lastRunAtIso,
      lastError
    };
  }

  async function ensureAvailable() {
    const binaryPath = resolveBinaryPath();
    let modelPath = resolveModelPath();

    if (!binaryPath) {
      status = "unavailable";
      lastError = "Binario whisper-cli nao encontrado. Defina WHISPER_CLI_PATH ou instale em userData/runtime.";
      logger.warn("whisper-cli unavailable", { lastError });
      return getStatus();
    }

    if (!modelPath) {
      if (modelManager) {
        const ensured = await modelManager.ensureModel("whisper");
        if (ensured.state === "ready") {
          modelPath = ensured.filePath;
        }
      }

      if (!modelPath) {
        status = "unavailable";
        lastError = "Modelo Whisper nao encontrado. Defina WHISPER_MODEL_PATH ou configure download via ModelManager.";
        logger.warn("whisper model unavailable", { lastError });
        return getStatus();
      }
    }

    status = "ready";
    return getStatus();
  }

  function writeChunkToTempWav(chunkBase64) {
    const tempDir = path.join(os.tmpdir(), "clone-perssua-stt");
    if (!fs.existsSync(tempDir)) {
      fs.mkdirSync(tempDir, { recursive: true });
    }

    const filePath = path.join(tempDir, `chunk-${Date.now()}-${Math.random().toString(16).slice(2)}.wav`);
    const audioBuffer = Buffer.from(chunkBase64, "base64");
    fs.writeFileSync(filePath, audioBuffer);
    return filePath;
  }

  function parseWhisperOutput(stdoutText) {
    const normalized = (stdoutText || "").trim();
    if (!normalized) {
      return "";
    }

    const lines = normalized
      .split(/\r?\n/)
      .map((line) => line.trim())
      .filter(Boolean)
      .filter((line) => !line.startsWith("[") || line.includes("] "));

    return lines.join(" ").trim();
  }

  async function transcribeChunk(params) {
    const availability = await ensureAvailable();
    if (availability.state !== "ready") {
      throw new Error(availability.lastError || "Runtime Whisper indisponivel.");
    }

    const tempAudioPath = writeChunkToTempWav(params.chunkBase64 || "");
    const binaryPath = availability.binaryPath;
    const modelPath = availability.modelPath;
    const language = params.language || "auto";

    status = "running";
    lastError = "";
    lastRunAtIso = new Date().toISOString();

    return new Promise((resolve, reject) => {
      const args = ["-m", modelPath, "-f", tempAudioPath, "-otxt"];
      if (language !== "auto") {
        args.push("-l", language);
      }

      const child = spawn(binaryPath, args, {
        stdio: ["ignore", "pipe", "pipe"],
        windowsHide: true
      });

      let stdout = "";
      let stderr = "";

      child.stdout.on("data", (chunk) => {
        stdout += String(chunk || "");
      });

      child.stderr.on("data", (chunk) => {
        stderr += String(chunk || "");
      });

      child.on("error", (error) => {
        status = "error";
        lastError = error.message;
        try {
          fs.unlinkSync(tempAudioPath);
        } catch {}
        reject(error);
      });

      child.on("close", (code) => {
        status = code === 0 ? "ready" : "error";
        try {
          fs.unlinkSync(tempAudioPath);
        } catch {}

        if (code !== 0) {
          lastError = stderr.trim() || `whisper-cli exited with code ${code}`;
          reject(new Error(lastError));
          return;
        }

        const text = parseWhisperOutput(stdout);
        resolve({
          text,
          isFinal: true
        });
      });
    });
  }

  function stop() {
    status = status === "running" ? "ready" : status;
    return getStatus();
  }

  return {
    ensureAvailable,
    getStatus,
    transcribeChunk,
    stop
  };
}

module.exports = {
  createWhisperCliManager
};
